import React, { useEffect, useState, useRef } from 'react';
import './GlassMemPage.css';

/* ─── Pentagon logo SVG (dark navy + blue fills for light bg) ─── */
const PentagonLogo = ({ size = 32 }) => (
  <svg width={size} height={size} viewBox="0 0 1023 977" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M1022.52 373.339C1021.96 372.826 1021.43 372.662 1020.91 372.849C952.332 397.256 883.755 421.662 815.182 446.069C815.175 446.069 815.165 446.069 815.152 446.069L813.942 446.119L355.892 113.329C355.837 113.291 355.792 113.24 355.762 113.181C355.731 113.122 355.715 113.055 355.715 112.988C355.715 112.921 355.731 112.854 355.762 112.793C355.792 112.732 355.837 112.68 355.892 112.639L510.772 0.108917C510.873 0.0363731 510.996 -0.00173594 511.121 6.07308e-05C511.247 0.0018574 511.37 0.0434618 511.472 0.118911C529.505 13.2856 698.222 135.869 1017.62 367.869C1020.3 369.816 1021.92 371.036 1022.47 371.529C1022.89 371.896 1022.91 372.499 1022.52 373.339Z" fill="#0d0d12"/>
    <path d="M612.422 504.079L415.752 576.149C372.365 546.522 329.145 517.002 286.092 487.589C259.552 469.462 232.819 451.019 205.892 432.259C179.252 413.692 152.602 395.125 125.942 376.559L54.1621 326.559L209.062 215.459C209.316 215.275 209.621 215.176 209.935 215.176C210.249 215.176 210.556 215.275 210.812 215.459L612.422 504.079Z" fill="#0d0d12"/>
    <path d="M54.1621 326.559L125.942 376.559L294.232 916.569L273.442 976.189L189.202 976.149C189.094 976.149 188.99 976.116 188.904 976.054C188.817 975.993 188.754 975.907 188.722 975.809L0.0420414 366.449C-0.0162491 366.256 -0.0138681 366.051 0.0488316 365.861C0.111531 365.671 0.231459 365.506 0.392048 365.389L54.1621 326.559Z" fill="url(#pg_grad)"/>
    <path d="M612.421 504.079C612.468 506.719 612.085 508.646 611.271 509.859C607.945 517.606 605.398 525.519 603.631 533.599L459.441 975.729C459.399 975.868 459.312 975.99 459.195 976.076C459.078 976.163 458.937 976.209 458.791 976.209L273.441 976.189L294.231 916.569C294.578 916.289 294.835 915.916 295.001 915.449C335.255 802.876 375.511 690.306 415.771 577.739C416.158 576.666 416.151 576.136 415.751 576.149L612.421 504.079Z" fill="#2160fd"/>
    <path d="M960.793 563.233L827.393 973.609C827.337 973.781 827.229 973.93 827.084 974.036C826.938 974.142 826.763 974.199 826.583 974.199H642.673C642.615 974.199 642.558 974.186 642.507 974.159C642.456 974.133 642.411 974.094 642.378 974.047C642.345 974 642.323 973.946 642.315 973.889C642.307 973.832 642.314 973.773 642.333 973.719L813.942 446.119L815.152 446.069H815.183C869.944 426.578 924.709 407.088 979.475 387.597L979.5 387.5L1023 372L960.793 563.233Z" fill="#2160fd"/>
    <defs>
      <linearGradient id="pg_grad" x1="147.116" y1="326.559" x2="147.116" y2="976.189" gradientUnits="userSpaceOnUse">
        <stop stopColor="#2160fd"/>
        <stop offset="1" stopColor="#1a4ee0"/>
      </linearGradient>
    </defs>
  </svg>
);

/* ─── Scroll reveal hook ─── */
function useReveal() {
  useEffect(() => {
    const obs = new IntersectionObserver(
      entries => entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('is-visible'); }),
      { threshold: 0.08 }
    );
    document.querySelectorAll('.gm-reveal').forEach(el => obs.observe(el));
    return () => obs.disconnect();
  }, []);
}

/* ─── Copy to clipboard helper ─── */
function useCopy(text, ms = 1800) {
  const [copied, setCopied] = useState(false);
  const copy = () => {
    navigator.clipboard.writeText(text).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), ms);
    });
  };
  return [copied, copy];
}

/* ─── Integration strip items ─── */
const INTEGRATIONS = [
  'OpenAI GPT-4o', 'Claude 3.5', 'LangChain', 'LlamaIndex', 'CrewAI',
  'AutoGen', 'Pinecone', 'Weaviate', 'Qdrant', 'Redis', 'PostgreSQL',
  'Supabase', 'Vercel AI SDK', 'FastAPI', 'Next.js', 'Modal',
];

/* ─── Problem cards ─── */
const PROBLEMS = [
  {
    icon: '🧠',
    tag: '// CONTEXT_LOSS',
    title: 'Agents forget between calls',
    body: 'Every invocation starts cold. Your agent re-fetches the same data, re-makes the same decisions, and burns tokens on context it already computed.',
    tags: ['stateless', 'cold-start', 'token-waste'],
    color: '#ef4444',
    viz: (
      <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
        {['Run 1 → context lost', 'Run 2 → context lost', 'Run 3 → context lost'].map((t, i) => (
          <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 8, fontFamily: 'var(--font-mono)', fontSize: 11, color: 'var(--text-3)' }}>
            <span style={{ width: 6, height: 6, borderRadius: '50%', background: '#ef4444', display: 'inline-block', flexShrink: 0 }} />
            {t}
          </div>
        ))}
      </div>
    ),
  },
  {
    icon: '💸',
    tag: '// TOKEN_BURN',
    title: 'Redundant computation everywhere',
    body: 'Without memory, every pipeline re-derives the same facts from scratch. At scale, this silently drains your LLM budget.',
    tags: ['cost', 'latency', 'redundancy'],
    color: '#f59e0b',
    viz: (
      <div style={{ fontFamily: 'var(--font-mono)', fontSize: 11, color: 'var(--text-3)' }}>
        {['$0.12 wasted', '$0.31 wasted', '$0.09 wasted'].map((t, i) => (
          <div key={i} style={{ display: 'flex', justifyContent: 'space-between', padding: '4px 0', borderBottom: '1px solid var(--border)' }}>
            <span>run_{i + 1}</span><span style={{ color: '#f59e0b' }}>{t}</span>
          </div>
        ))}
      </div>
    ),
  },
  {
    icon: '🔀',
    tag: '// RACE_CONDITIONS',
    title: 'Multi-agent state conflicts',
    body: 'When multiple agents share state without coordination, you get race conditions, stale reads, and unpredictable behaviour.',
    tags: ['multi-agent', 'race', 'stale-state'],
    color: '#7c3aed',
    viz: (
      <div style={{ fontFamily: 'var(--font-mono)', fontSize: 11, color: 'var(--text-3)' }}>
        {['agent_a writes key', 'agent_b reads stale', 'conflict → undefined'].map((t, i) => (
          <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '3px 0' }}>
            <span style={{ width: 5, height: 5, borderRadius: '50%', background: '#7c3aed', display: 'inline-block', flexShrink: 0 }} />
            {t}
          </div>
        ))}
      </div>
    ),
  },
];

/* ─── Solution features ─── */
const FEATURES = [
  { icon: '⚡', title: 'Sub-10ms reads', body: 'Hot-path memory retrieval from an in-process cache. Your agents never block on state.' },
  { icon: '🔄', title: 'Automatic sync', body: 'Writes propagate instantly across all agent replicas via a conflict-free CRDT layer.' },
  { icon: '🧩', title: 'Schema-optional', body: 'Store structured facts or raw strings — GlassMem adapts to whatever shape your agent needs.' },
  { icon: '🔒', title: 'Scoped isolation', body: 'Per-agent, per-session, or per-tenant namespaces with zero configuration.' },
];

/* ─── Tech specs ─── */
const TECH_ITEMS = [
  { num: '01', title: 'CRDT-backed conflict resolution', body: 'Multi-agent writes never conflict. GlassMem uses a grow-only register CRDT so concurrent writes converge automatically.' },
  { num: '02', title: 'Pluggable storage backends', body: 'Redis, PostgreSQL, Supabase, or in-memory. Swap backends without changing agent code.' },
  { num: '03', title: 'Streaming event bus', body: 'Every memory mutation emits an event. Subscribe in real-time and build reactive agent pipelines.' },
  { num: '04', title: 'OpenTelemetry native', body: 'Full trace context propagated through every read and write. Debug exactly where memory slows your agent.' },
  { num: '05', title: 'Framework agnostic', body: 'Works with LangChain, LlamaIndex, CrewAI, AutoGen, or plain Python/TypeScript. No lock-in.' },
];

/* ─── Ecosystem ─── */
const ECOSYSTEM = [
  { name: 'OpenAI', tag: 'LLM' }, { name: 'Anthropic', tag: 'LLM' }, { name: 'Google Gemini', tag: 'LLM' },
  { name: 'LangChain', tag: 'Framework' }, { name: 'LlamaIndex', tag: 'Framework' }, { name: 'CrewAI', tag: 'Framework' },
  { name: 'Pinecone', tag: 'Vector' }, { name: 'Weaviate', tag: 'Vector' }, { name: 'Qdrant', tag: 'Vector' },
  { name: 'Redis', tag: 'Cache' }, { name: 'PostgreSQL', tag: 'Storage' }, { name: 'Supabase', tag: 'Storage' },
];

/* ─── Pricing ─── */
const PLANS = [
  {
    tier: 'Hobby',
    price: '$0',
    period: '/mo',
    desc: 'Perfect for side projects',
    featured: false,
    features: ['1 project', '100K memory ops / mo', '1-day TTL', 'Community support', 'In-memory backend'],
  },
  {
    tier: 'Pro',
    price: '$49',
    period: '/mo',
    desc: 'For production agents',
    featured: true,
    features: ['Unlimited projects', '10M memory ops / mo', '90-day TTL', 'Priority support', 'Redis + PG backends', 'Streaming events'],
  },
  {
    tier: 'Enterprise',
    price: 'Custom',
    period: '',
    desc: 'For teams at scale',
    featured: false,
    features: ['SLA guarantee', 'Unlimited ops', 'Custom TTL', 'Dedicated support', 'VPC deployment', 'SOC 2 compliant'],
  },
];

/* ─── Hero events (cycling) ─── */
const EVENTS = [
  { emoji: '🧠', method: 'memory.write()', detail: 'user_42 · intent="book_flight"', time: '0ms', color: '#2160fd' },
  { emoji: '⚡', method: 'memory.read()', detail: 'user_42 · hit_rate=100%', time: '4ms', color: '#12b76a' },
  { emoji: '🔄', method: 'memory.sync()', detail: 'agent_pool · 3 replicas', time: '8ms', color: '#f59e0b' },
  { emoji: '🔒', method: 'memory.scope()', detail: 'tenant_99 · isolated ns', time: '1ms', color: '#7c3aed' },
  { emoji: '📡', method: 'event.emit()', detail: 'key=last_intent · subscribers=2', time: '2ms', color: '#2160fd' },
];

/* ══════════════════════════════════════════════
   MAIN COMPONENT
══════════════════════════════════════════════ */
export function GlassMemPage() {
  useReveal();

  /* Navbar scroll state */
  const [scrolled, setScrolled] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);
  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 12);
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  /* Hero event cycling */
  const [activeEvent, setActiveEvent] = useState(0);
  useEffect(() => {
    const t = setInterval(() => setActiveEvent(i => (i + 1) % EVENTS.length), 1600);
    return () => clearInterval(t);
  }, []);

  /* Install copy */
  const [copied, copy] = useCopy('npm install glassmem');

  return (
    <div>
      {/* ── NAVBAR ────────────────────────────────── */}
      <nav className={`gm-nav${scrolled ? ' gm-nav--scrolled' : ''}`}>
        <div className="gm-nav__inner">
          <a href="/" className="gm-nav__logo">
            <PentagonLogo size={26} />
            <span className="gm-nav__wordmark">GlassMem</span>
          </a>

          <div className="gm-nav__links">
            {['Features', 'How it works', 'Ecosystem', 'Pricing'].map(l => (
              <a key={l} href={`#${l.toLowerCase().replace(/ /g, '-')}`} className="gm-nav__link">{l}</a>
            ))}
            <div className="gm-nav__divider" />
            <a href="https://docs.glassmem.ai" className="gm-nav__link">Docs</a>
            <a href="https://github.com/glassmem" className="gm-nav__link">GitHub</a>
            <div className="gm-nav__divider" />
            <a href="#pricing" className="gm-btn gm-btn--primary" style={{ padding: '7px 16px', fontSize: 13 }}>Get started</a>
          </div>

          <button className="gm-nav__mobile-toggle" onClick={() => setMobileOpen(o => !o)} aria-label="Menu">
            {mobileOpen ? '✕' : '☰'}
          </button>
        </div>

        <div className={`gm-nav__mobile-menu${mobileOpen ? ' is-open' : ''}`}>
          {['Features', 'How it works', 'Ecosystem', 'Pricing', 'Docs', 'GitHub'].map(l => (
            <a key={l} href={`#${l.toLowerCase().replace(/ /g, '-')}`}
              className="gm-nav__mobile-link"
              onClick={() => setMobileOpen(false)}>{l}</a>
          ))}
        </div>
      </nav>

      {/* ── HERO ──────────────────────────────────── */}
      <section className="gm-hero">
        <div className="gm-hero__bg-dots" />
        <div className="gm-hero__bg-glow" />
        <div className="gm-hero__bg-fade" />

        <div className="gm-container">
          <div className="gm-hero__inner">
            {/* Badge */}
            <div className="gm-hero__badge gm-fade-up">
              <span className="gm-badge">
                <span className="gm-badge__dot" />
                Now in public beta · v0.4
